#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; long long A,B; char s[105];
        scanf("%d %lld %lld",&N,&A,&B);
        scanf("%s",s);
        long long cnt0=0,cnt1=0;
        for(int i=0;i<N;i++){
            if(s[i]=='0') cnt0++; else cnt1++;
        }
        printf("%lld\n",cnt0*A+cnt1*B);
    }
    return 0;
}

